import{C as t,o as l,c as n,a5 as a,E as o}from"./chunks/framework.CW28V7p_.js";const c=JSON.parse('{"title":"3. Cargo / Rust","description":"","frontmatter":{},"headers":[],"relativePath":"module-0/3-cargo.md","filePath":"module-0/3-cargo.md","lastUpdated":1780937944000}'),r={name:"module-0/3-cargo.md"},k=Object.assign(r,{setup(d){const i={id:"m0-3-cargo",title:"🧠 Mini-check: Cargo / Rust",intro:"3 питання щоб перевірити cargo концепти.",questions:[{type:"mcq",q:"Що робить флаг --locked у cargo install (обери всі правильні)?",options:["Забороняє cargo resolveити dependencies наново, використовує точно версії з Cargo.lock","Гарантує reproducible builds — той самий source + lock дають bit-exact binary","Падає з помилкою якщо Cargo.lock не synced з Cargo.toml","Encrypts the binary з ключем lock-файлу"],correct:[0,1,2],explanation:"Locked = lock file is authoritative. Cargo читає тільки звідти, не намагається upgradeити deps. Якщо lock не sync з toml — fail. Це і дає reproducibility. Encryption тут ні до чого."},{type:"scenario",q:'Ти запускаєш cargo install --locked --path validator --root /home/solana/ag-v0.4.2. Build пройшов через 5 хвилин з помилкою: "error: binary agave-validator already exists in destination". Що робити (опиши 2 варіанти fix)?',ideal:`Варіант 1: додати --force flag (cargo install --locked --force --path validator --root /home/solana/ag-v0.4.2). Це скаже cargo переписати existing binary. Це швидкий fix який і використовується у agave cargo-install-all.sh через sed додавання --force.

Варіант 2: видалити старий binary спочатку (sudo rm /home/solana/ag-v0.4.2/bin/agave-validator), потім перезапустити cargo install. Менш зручно але можна якщо --force з якоїсь причини не підходить.

Причина error: cargo install за замовчуванням refuses overwrite — захист від випадкового перепису.`,explanation:"Ключові пункти: знати про --force flag і чому він треба (cargo захищає від overwrite), знати альтернативу (видалити вручну). Якщо ти описала обидва підходи + причину — це повна відповідь."},{type:"command",q:"Напиши команду щоб подивитись скільки RAM потрібно agave для build (підказка: вільну RAM).",accepts:["free -h","free -m","free","free -g","cat /proc/meminfo"],ideal:"free -h",explanation:"free -h показує memory usage у human-readable форматі (GB/MB). free -m у мегабайтах, free -g у гігабайтах. cat /proc/meminfo дає raw data — теж працює але менш зручно. Для agave потрібно ~16 GB вільної RAM."}]};return(p,s)=>{const e=t("Quiz");return l(),n("div",null,[s[0]||(s[0]=a("",75)),o(e,{data:i}),s[1]||(s[1]=a("",6))])}}});export{c as __pageData,k as default};
